    @Override

public void onResponse(Call<CozeChatResponse> call, Response<CozeChatResponse> response) {
    if (response.isSuccessful() && response.body() != null && response.body().getMessages() != null) {
        for (CozeChatResponse.Message message : response.body().getMessages()) {
            if ("assistant".equals(message.getRole()) && "answer".equals(message.getType())) {
                String content = message.getContent();
                if (content != null && !content.isEmpty()) {

                    parseContent(content, callback);
                    return; // We found the answer, exit.
                }
            }
        }
        callback.onError("No valid answer found in AI response.");
    } else {
        callback.onError("Failed to get response from AI. Code: " + response.code());
    }
}

        public void onFailure(Call<CozeChatResponse> call, Throwable t) {
            callback.onError("AI API call failed: " + t.getMessage());
        }
    });
}

private void parseContent(String content, final AiTaskParserCallback callback) {
    List<String> lines = Arrays.asList(content.split("\n"));
    List<AiTask> parsedTasks = new ArrayList<>();

StringBuilder introBuilder = new StringBuilder();

// 匹配类似 "(30分钟)" 或 "（30分钟）"
Pattern pattern = Pattern.compile("(?:（|\\()(\\d+)\\s*分钟?(?:）|\\))");

for (String line : lines) {
    String description = line.trim();
    int duration = 25; // 默认时长

    Matcher matcher = pattern.matcher(line);
    if (matcher.find()) {

        parsedTasks.add(new AiTask(description, duration));
    }

    if (!parsedTasks.isEmpty()) {
        callback.onSuccess(introBuilder.toString().trim(), parsedTasks);
    } else {
        introBuilder.append("\n(无法解析任务时长，将显示原始文本)");
        callback.onSuccess(introBuilder.toString().trim(), new ArrayList<>());
    }
}

