private String getMimeType(String fileName) {
    if (fileName.endsWith(".json")) {
        return "application/json";
    } else if (fileName.endsWith(".csv")) {
        return "text/csv";
    } else if (fileName.endsWith(".txt")) {
        return "text/plain";
    } else {
        return "*/*";
    }
}

private Uri getFileUri(File file) {
